import sys

def get_min_sum(numbers):
    min_sum = 0
    for number in numbers:
        min_sum += int(number)
    return min_sum

def restore_numbers(numbers):
    restored_numbers = []
    for number in numbers:
        restored_number = ""
        for digit in number:
            if digit.isdigit():
                restored_number += digit
            else:
                restored_number += str(ord(digit) - ord('a'))
        restored_numbers.append(restored_number)
    return restored_numbers

def main():
    n = int(sys.stdin.readline().strip())
    numbers = []
    for i in range(n):
        numbers.append(sys.stdin.readline().strip())
    restored_numbers = restore_numbers(numbers)
    min_sum = get_min_sum(restored_numbers)
    print(min_sum)

if __name__ == "__main__":
    main()
